22	static constexpr float MAX_INIT_VAL = -1e30;    // Prevent (-inf) - (-inf) = nan
23	using cutlass::arch::fence_view_async_shared;
24	using cutlass::arch::NamedBarrier;
25	using fp8_e8m0 = __nv_fp8_e8m0;
