27	template<
28	    typename Tensor0,
29	    typename Tensor1,
30	    typename Tensor2
31	>
32	__forceinline__ __device__ void scale_softmax(
33	    Tensor0 &rP,
34	    Tensor1 &rS,
35	    Tensor2 &rO,
36	    float scale_softmax_log2,
37	    float sScale[],
38	    float rM[2],
39	    float rL[2],
40	    bool is_kv_valid[],
41	    int block_idx,
42	    int idx_in_warpgroup
43	) {
44	    float scale_for_olds[2];
45	    CUTE_UNROLL
46	    for (int local_row_idx = 0; local_row_idx < 2; ++local_row_idx) {
47	        Tensor cur_rP = flatten(rP(make_coord(_, local_row_idx, _), _, _));
48	        Tensor cur_rS = flatten(rS(make_coord(_, local_row_idx, _), _, _));
49	        Tensor cur_rO = flatten(rO(make_coord(_, local_row_idx, _), _, _));
50	
51	        float cur_max = -INFINITY;
52	        CUTE_UNROLL
53	        for (int i = 0; i < size(cur_rP); ++i) {
54	            if (!is_kv_valid[(i&1)+(i/2)*8+(idx_in_warpgroup%4)*2])
55	                cur_rP(i) = -INFINITY;
56	            cur_max = max(cur_max, cur_rP(i));
57	        }
58	        cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 1));
59	        cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 2));
60	
61	        cur_max *= scale_softmax_log2;
62	        float old_max = rM[local_row_idx];
63	        rM[local_row_idx] = max(cur_max, old_max);
64	        float scale_for_old = exp2f(old_max - rM[local_row_idx]);
65	        scale_for_olds[local_row_idx] = scale_for_old;
66	
67	        CUTE_UNROLL
68	        for (int i = 0; i < size(cur_rO); ++i) {
69	            cur_rO(i) *= scale_for_old;
70	        }
71	
72	        float cur_sum = 0;
73	        CUTE_UNROLL
74	        for (int i = 0; i < size(cur_rP); ++i) {
75	            cur_rP(i) = exp2f(cur_rP(i)*scale_softmax_log2 - rM[local_row_idx]);
76	            cur_rS(i) = (bf16)cur_rP(i);
77	            cur_sum += cur_rP(i);
78	        }
79	
80	        rL[local_row_idx] = rL[local_row_idx]*scale_for_old + cur_sum;
81	    }
82	    if (idx_in_warpgroup%4 == 0)
83	        *(float2*)(sScale + 2*(idx_in_warpgroup/4)) = *(float2*)(scale_for_olds);
84	}
85	
86	template<ModelType MODEL_TYPE, int NUM_HEADS>
87	template<typename TMAParams>
88	__device__ void KernelTemplate<MODEL_TYPE, NUM_HEADS>::devfunc(const SparseAttnDecodeParams &params, const TMAParams &tma_params) {
89	#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ == 900)) || (defined(__CLION_IDE__) || defined(__VSCODE_IDE__))
90	    const int head_block_idx = NUM_M_BLOCKS == 1 ? 0 : blockIdx.x;
91	    const int s_q_idx = blockIdx.y;
92	    const int partition_idx = blockIdx.z;
93	    const int idx_in_cluster = CLUSTER_SIZE == 1 ? 0 : head_block_idx % 2;
94	    const int warpgroup_idx = cutlass::canonical_warp_group_idx();
95	    const int idx_in_warpgroup = threadIdx.x % 128;
96	    const int warp_idx = cutlass::canonical_warp_idx_sync();
97	
98	    // Define shared tensors
99	    extern __shared__ char wksp_buf[];
100	    SharedMemoryPlan &plan = *reinterpret_cast<SharedMemoryPlan*>(wksp_buf);
101	    Tensor sQ = make_tensor(make_smem_ptr(plan.q.data()), SmemLayoutQ{});
102	    Tensor sOBuf = make_tensor(make_smem_ptr(plan.u.oBuf.data()), SmemLayoutOBuf{});
103	    Tensor sOAccumBuf = make_tensor(make_smem_ptr(plan.u.oAccumBuf.data()), SmemLayoutOAccumBuf{});
104	    Tensor sS = make_tensor(make_smem_ptr(plan.s.data()), SmemLayoutS{});
105	    float* sM = plan.sM;
106	    float* sL = plan.sL;
107	    float* sScale = plan.sScale;
108	    
109	    // Prefetch TMA descriptors
110	    if (warp_idx == 0 && elect_one_sync()) {
111	        cute::prefetch_tma_descriptor(tma_params.tma_Q.get_tma_descriptor());
112	        cute::prefetch_tma_descriptor(&tma_params.tensor_map_o);
113	    }
114	    
115	    // Initialize TMA barriers
116	    if (warp_idx == 0 && elect_one_sync()) {
117	        plan.bar_q.init(1);
118	        if constexpr (CLUSTER_SIZE == 2) {
119	            CUTE_UNROLL
120	            for (int i = 0; i < NUM_K_BUFS; ++i) {
121	                plan.bar_k_local_ready[i].init(128);
122	                plan.bar_k_remote_ready[i].init(1);
123	                plan.bar_k_avail[i].init(4);
124	            }
125	        } else {
126	            CUTE_UNROLL
127	            for (int i = 0; i < NUM_K_BUFS; ++i) {
128	                plan.bar_k_local_ready[i].init(128);
129	                plan.bar_k_avail[i].init(256);
130	            }
131	        }
132	        cutlass::arch::fence_barrier_init();
133	    }
134	    ku::barrier_cluster_arrive_relaxed();
135	
136	    int bar_phase_k = 0; // Don't use array here to prevent using local memory
137	
138	    // Programmatic Dependent Launch: Wait for the previous kernel to finish
139	    // Don't use PDL because of compiler bugs!
140	    // cudaGridDependencySynchronize();
141	    
142	    DecodingSchedMeta sched_meta = params.tile_scheduler_metadata_ptr[partition_idx];
143	
144	    if (sched_meta.begin_req_idx >= params.b) return;
145	
146	    if (warp_idx == 0 && elect_one_sync()) {
147	        Tensor gQ = flat_divide(
148	            tma_params.tma_Q.get_tma_tensor(tma_params.shape_Q)(_, _, s_q_idx, sched_meta.begin_req_idx),
149	            Tile<Int<BLOCK_M>, Int<HEAD_DIM_K>>{}
150	        )(_, _, head_block_idx, _0{});
151	        launch_tma_copy(tma_params.tma_Q, gQ, sQ, plan.bar_q, TMA::CacheHintSm90::EVICT_FIRST);
152	        plan.bar_q.arrive_and_expect_tx(BLOCK_M*HEAD_DIM_K*sizeof(bf16));
153	    }
154	
155	    ku::barrier_cluster_wait_acquire();
156	
157	    struct MainloopArgs {
158	        int start_block_idx, end_block_idx;
159	        bool is_no_split;
160	
161	        // The following fields are only valid for MODEL1
162	        int topk_length, extra_topk_length, num_orig_kv_blocks;
163	    };
164	    auto get_cur_req_info = [&](int batch_idx) -> MainloopArgs {
165	        MainloopArgs args;
166	        int total_topk_padded;
167	        if constexpr (MODEL_TYPE == ModelType::V32) {
168	            total_topk_padded = params.topk;
169	        } else {
170	            int topk_length = params.topk_length ? __ldg(params.topk_length + batch_idx) : params.topk;
171	            int orig_topk_padded = max(ku::ceil(topk_length, (int)TOPK_BLOCK_SIZE), (int)TOPK_BLOCK_SIZE);
172	            int extra_topk_length = params.extra_topk_length ? __ldg(params.extra_topk_length + batch_idx) : params.extra_topk;
173	            total_topk_padded = orig_topk_padded + ku::ceil(extra_topk_length, (int)TOPK_BLOCK_SIZE);
174	            args.topk_length = topk_length;
175	            args.extra_topk_length = extra_topk_length;
176	            args.num_orig_kv_blocks = orig_topk_padded / TOPK_BLOCK_SIZE;
177	        }
178	
179	        args.start_block_idx = batch_idx == sched_meta.begin_req_idx ? sched_meta.begin_block_idx : 0;
180	        args.end_block_idx = batch_idx == sched_meta.end_req_idx ? sched_meta.end_block_idx : total_topk_padded / TOPK_BLOCK_SIZE;
181	        args.is_no_split = batch_idx == sched_meta.begin_req_idx ? !sched_meta.is_first_req_splitted : (batch_idx == sched_meta.end_req_idx ? !sched_meta.is_last_req_splitted : true);
182	
183	        return args;
184	    };
185	
186	    if (warpgroup_idx == 0) {
187	        cutlass::arch::warpgroup_reg_alloc<192>();
188	
189	        TiledMMA tiled_mma_QK = TiledMMA_QK{};
190	        ThrMMA thr_mma_QK = tiled_mma_QK.get_slice(idx_in_warpgroup);
191	        TiledMMA tiled_mma_PV = TiledMMA_PV_LocalP{};
192	        ThrMMA thr_mma_PV = tiled_mma_PV.get_slice(idx_in_warpgroup);
193	        
194	        float rL[2], rM[2];
195	        Tensor rO = partition_fragment_C(TiledMMA_PV_LocalP{}, Shape<Int<BLOCK_M>, Int<HEAD_DIM_V/2>>{});
196	        Tensor rP = partition_fragment_C(TiledMMA_QK{}, Shape<Int<BLOCK_M>, Int<TOPK_BLOCK_SIZE>>{});
197	        Tensor rS = make_tensor<bf16>(partition_shape_A(TiledMMA_PV_LocalP{}, Shape<Int<BLOCK_M>, Int<TOPK_BLOCK_SIZE>>{}));
198	
199	        float rAttn_sink[2] = {-CUDART_INF_F, -CUDART_INF_F};
200	        if (params.attn_sink != nullptr) {
201	            for (int i = 0; i < 2; ++i) {
202	                int head_idx = head_block_idx*BLOCK_M + get_AorC_row_idx(i, idx_in_warpgroup);
203	                rAttn_sink[i] = __ldg((float*)params.attn_sink + head_idx) * CUDART_L2E_F;
204	            }
205	        }
206	
207	        #pragma unroll 1
208	        for (int batch_idx = sched_meta.begin_req_idx; batch_idx <= sched_meta.end_req_idx; ++batch_idx) {
209	            MainloopArgs args = get_cur_req_info(batch_idx);
210	
211	            rL[0] = rL[1] = 0.0f;
212	            rM[0] = rM[1] = MAX_INIT_VAL;
213	            cute::fill(rO, 0.);
214	
215	            // Wait for Q
216	            plan.bar_q.wait((sched_meta.begin_req_idx-batch_idx)&1);
217	
218	            CUTE_NO_UNROLL
219	            for (int block_idx = args.start_block_idx; block_idx < args.end_block_idx; block_idx++) {
220	                int buf_idx = (block_idx-args.start_block_idx) % NUM_K_BUFS;
221	                Tensor sK = make_tensor(make_smem_ptr(plan.u.k[buf_idx].data()), SmemLayoutK{});
222	                Tensor sV = make_tensor(make_smem_ptr(plan.u.k[buf_idx].data()), SmemLayoutHalfV{});
223	
224	                // Wait, issue WGMMA
225	                plan.bar_k_local_ready[buf_idx].wait(bar_phase_k>>buf_idx&1);
226	                if constexpr (CLUSTER_SIZE == 2) {
227	                    plan.bar_k_remote_ready[buf_idx].wait(bar_phase_k>>buf_idx&1);
228	                }
229	
230	                gemm<true, -1>(
231	                    tiled_mma_QK,
232	                    thr_mma_QK.partition_fragment_A(sQ),
233	                    thr_mma_QK.partition_fragment_B(sK),
234	                    rP
235	                );
236	
237	                bar_phase_k ^= 1<<buf_idx;
238	
239	                cute::warpgroup_wait<0>();
240	                
241	                // Calculate S = softmax(mask(scale(P)))
242	                if (block_idx != args.start_block_idx)
243	                    NamedBarrier::arrive_and_wait(256, NamedBarriers::sScale_and_sS_free);  // Make sure that sScale and sS is free
244	
245	                // Since in our case TOPK_BLOCK_SIZE == BLOCK_M, so we only need to do OOB checking for the last 2 blocks
246	                scale_softmax(rP, rS, rO, params.sm_scale_div_log2, sScale, rM, rL, plan.is_kv_valid[buf_idx], block_idx, idx_in_warpgroup);
247	
248	                // Store S into shared, inform warpgroup 1
249	                save_rPb_to_sP(rS, sS, idx_in_warpgroup);
250	                fence_view_async_shared();
251	
252	                // Issue O += S @ V
253	                gemm<false, -1>(
254	                    tiled_mma_PV,
255	                    rS,
256	                    thr_mma_PV.partition_fragment_B(sV),
257	                    rO
258	                );
259	
260	                NamedBarrier::arrive(256, NamedBarriers::sScale_and_sS_ready);
261	
262	                cute::warpgroup_wait<0>();
263	
264	                if constexpr (CLUSTER_SIZE == 2) {
265	                    plan.bar_k_avail[buf_idx].arrive(0, idx_in_warpgroup == 32);
266	                    plan.bar_k_avail[buf_idx].arrive(1, idx_in_warpgroup == 64);
267	                } else {
268	                    plan.bar_k_avail[buf_idx].arrive();
269	                }
270	            }
271	
272	            // Copy the next q
273	            if (threadIdx.x/32 == 0 && elect_one_sync()) {
274	                if (batch_idx != sched_meta.end_req_idx) {
275	                    Tensor gQ = flat_divide(
276	                        tma_params.tma_Q.get_tma_tensor(tma_params.shape_Q)(_, _, s_q_idx, batch_idx+1),
277	                        Tile<Int<BLOCK_M>, Int<HEAD_DIM_K>>{}
278	                    )(_, _, head_block_idx, _0{});
279	                    launch_tma_copy(tma_params.tma_Q, gQ, sQ, plan.bar_q, TMA::CacheHintSm90::EVICT_FIRST);
280	                    plan.bar_q.arrive_and_expect_tx(BLOCK_M*HEAD_DIM_K*sizeof(bf16));
281	                } else {
282	                    // This kernel is followed by the combine kernel, so we signal PDL here
283	                    cudaTriggerProgrammaticLaunchCompletion();
284	                }
285	            }
286	
287	            // Synchronize L and M across warpgroups
288	            rL[0] += __shfl_xor_sync(0xffffffff, rL[0], 1);
289	            rL[0] += __shfl_xor_sync(0xffffffff, rL[0], 2);
290	            rL[1] += __shfl_xor_sync(0xffffffff, rL[1], 1);
291	            rL[1] += __shfl_xor_sync(0xffffffff, rL[1], 2);
292	
293	            if (idx_in_warpgroup%4 == 0) {
294	                CUTE_UNROLL
295	                for (int i = 0; i < 2; ++i) {
296	                    int row = get_AorC_row_idx(i, idx_in_warpgroup);
297	                    sL[row] = rL[i];
298	                    sM[row] = rM[i];
299	                }
300	            }
301	            
302	            float o_scales[2];
303	            CUTE_UNROLL
304	            for (int i = 0; i < 2; ++i) {
305	                if (args.is_no_split) {
306	                    o_scales[i] = rL[i] == 0.0f ? 0.0f : __fdividef(1.0f, rL[i] + exp2f(rAttn_sink[i] - rM[i]));
307	                } else {
308	                    o_scales[i] = rL[i] == 0.0f ? 0.0f : __fdividef(1.0f, rL[i]);
309	                }
310	                if (idx_in_warpgroup%4 == 0) {
311	                    int row = get_AorC_row_idx(i, idx_in_warpgroup);
312	                    plan.sOScale[row] = o_scales[i];
313	                }
314	            }
315	
316	            // This is a synchronization point for warpgroup 0/1.
317	            // Warpgroup 0 should wait wg 1 for oBuf/oAccumBuf (overlapped with k) to be free
318	            // Warpgroup 1 should wait wg 0 for sL to be ready
319	            NamedBarrier::arrive_and_wait(256, NamedBarriers::oBuf_free_and_sL_ready);
320	
321	            CUTE_UNROLL
322	            for (int i = 0; i < 2; ++i)
323	                rL[i] = rL[i] == 0.0f ? 1.0f : rL[i];
324	            
325	            int start_head_idx = head_block_idx*BLOCK_M;
326	            int num_valid_seq_q = min(params.h_q - start_head_idx, BLOCK_M);
327	            if (args.is_no_split) {
328	                bf16* o_ptr = (bf16*)params.out + batch_idx*params.stride_o_b + s_q_idx*params.stride_o_s_q + start_head_idx*params.stride_o_h_q;	// (BLOCK_M, HEAD_DIM_V) : (params.stride_o_h_q, 1)
329	                Tensor gO = make_tensor(make_gmem_ptr(o_ptr), make_layout(
330	                    Shape<Int<BLOCK_M>, Int<HEAD_DIM_V>>{},
331	                    make_stride(params.stride_o_h_q, _1{})
332	                ));
333	                float* gSoftmaxLse = (float*)params.lse + batch_idx*params.stride_lse_b + s_q_idx*params.stride_lse_s_q + start_head_idx;	// (BLOCK_M) : (1)
334	
335	                store_o<true>(rO, gO, sOBuf, sOAccumBuf, plan, o_scales, tma_params, batch_idx, s_q_idx, head_block_idx, num_valid_seq_q, warpgroup_idx, idx_in_warpgroup);
336	
337	                int i = threadIdx.x;
338	                if (i < num_valid_seq_q) {
339	                    float cur_L = sL[i];
340	                    gSoftmaxLse[i] = cur_L == 0.0f ? INFINITY : logf(cur_L) + sM[i] / (float)M_LOG2E;
341	                }
342	
343	                cute::tma_store_wait<0>();
344	            } else {
345	                int n_split_idx = batch_idx == sched_meta.begin_req_idx ? sched_meta.begin_split_idx : 0;
346	                int split_idx = __ldg(params.num_splits_ptr+batch_idx) + n_split_idx;
347	                float* oaccum_ptr = (float*)params.o_accum + split_idx*params.stride_o_accum_split + s_q_idx*params.stride_o_accum_s_q + start_head_idx*params.stride_o_accum_h_q;	// (BLOCK_M, HEAD_DIM_V) : (params.stride_o_accum_h_q, 1)
