20	// Adapted from https://github.com/Dao-AILab/flash-attention/blob/cdaf2de6e95cb05400959b5ab984f66e4c7df317/hopper/utils.h
21	template <bool zero_init=false, int wg_wait=0, bool arrive=true, bool commit=true, typename Tensor0, typename Tensor1, typename Tensor2, typename TiledMma>
22	__forceinline__ __device__ void gemm(TiledMma &tiled_mma, Tensor0 const &tCrA, Tensor1 const &tCrB, Tensor2 &tCrC) {
23	    constexpr bool Is_RS = !cute::is_base_of<cute::GMMA::DescriptorIterator, typename TiledMma::FrgTypeA>::value;
24	    // Need to cast away const on tCrA since warpgroup_fence_operand doesn't take const
25	    if constexpr (Is_RS) { cute::warpgroup_fence_operand(const_cast<Tensor0 &>(tCrA)); }
26	    warpgroup_fence_operand(tCrC);
27	    if constexpr (arrive) {
28	        warpgroup_arrive();
29	    }
30	    if constexpr (zero_init) {
31	        tiled_mma.accumulate_ = GMMA::ScaleOut::Zero;
